import{_ as i,p as a,q as e,Y as l}from"./framework-aa5c4115.js";const t={},r=l('<h1 id="react编程思想" tabindex="-1"><a class="header-anchor" href="#react编程思想" aria-hidden="true">#</a> React编程思想</h1><h2 id="react的设计理念" tabindex="-1"><a class="header-anchor" href="#react的设计理念" aria-hidden="true">#</a> React的设计理念</h2><ul><li>单向数据流</li><li>虚拟DOM</li><li>组件化</li></ul><p><strong>单向数据流</strong></p><ul><li>数据与界面绑定</li><li>单向渲染</li><li>就好像一个函数，同样的输入，同样的输出</li></ul><p><strong>虚拟DOM</strong></p><ul><li>类似Docker或VMware的Snapshot快照技术</li></ul><p><strong>组件化</strong></p><ul><li>保持交互一致性</li><li>保持视觉风格的统一</li><li>便于程序员互相之间的协作</li></ul><h2 id="react哲学" tabindex="-1"><a class="header-anchor" href="#react哲学" aria-hidden="true">#</a> React哲学</h2><ul><li>将设计好的 UI 划分为组件层级</li><li>用 React 创建一个静态版本</li><li>确定 UI state 的最小（且完整）表示</li><li>确定 state 放置的位置</li><li>添加反向数据流</li></ul><h2 id="react组件的生命周期" tabindex="-1"><a class="header-anchor" href="#react组件的生命周期" aria-hidden="true">#</a> React组件的生命周期</h2><ul><li>Mounting: 创建虚拟DOM，渲染UI</li><li>Updating: 更新虚拟DOM，重新渲染UI</li><li>Unmounting: 删除虚拟DOM，移除UI</li></ul>',13),n=[r];function c(s,h){return a(),e("div",null,n)}const d=i(t,[["render",c],["__file","Reactbianchengsixiang.html.vue"]]);export{d as default};
